const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
const action = body.action || (body.submission_id ? 'update' : 'create');
if (!['create','update'].includes(action)) return { json: { _empty: true, status: 400, error: 'action must be create or update' } };
if (action === 'create' && !body.carrier_id) return { json: { _empty: true, status: 400, error: 'carrier_id required for create' } };
if (action === 'update' && !body.submission_id) return { json: { _empty: true, status: 400, error: 'submission_id required for update' } };
return { json: { token, body, action } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
const e = $('Extract').first().json;
const b = e.body;
const action = e.action;
const now = new Date().toISOString();
// Build PATCH/POST payload; auto-set timestamps based on status.
const payload = {};
const fields = ['carrier_id','lead_id','advisor_id','product_line','applicant_name','policy_number','face_amount_cents','annual_premium_cents','expected_commission_cents','decline_reason','notes','policy_application_id'];
fields.forEach(function (k) { if (b[k] !== undefined) payload[k] = b[k]; });
if (b.submission_status) {
  payload.submission_status = b.submission_status;
  if (b.submission_status === 'submitted' && !b.submitted_at) payload.submitted_at = now;
  if (['approved','declined'].indexOf(b.submission_status) >= 0 && !b.underwriting_decision_at) payload.underwriting_decision_at = now;
  if (b.submission_status === 'issued' && !b.policy_issued_at) payload.policy_issued_at = now;
}
payload.updated_at = now;
if (action === 'create') {
  payload.client_id = row.client_id;
  if (!payload.submission_status) payload.submission_status = 'in_progress';
}
return { json: { _ok: true, action: action, submission_id: b.submission_id || null, payload: payload, user_id: row.user_id } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
return { json: { ok: true, submission: row } };
